// frontend/packages/ui/src/demo_chats/newsletterChatStore.ts
//
// Registry for newsletter-derived demo chats.
//
// Each issue of the OpenMates newsletter (Updates & Announcements or
// Tips & Tricks) gets a DemoChat entry here. The email links to a public
// SEO page at /announcements/<slug> or /tips/<slug> which both:
//   1. Serve a crawlable body to search engines (and email preview bots).
//   2. Redirect humans to the SPA deep link /#chat-id=<kind>-<slug>.
//
// The entries below are generated by backend/scripts/publish_newsletter.py
// — do not hand-edit except to adjust order or flip is_active.

import type { DemoChat } from "./types";

// === Generated newsletter chat imports (managed by publish_newsletter.py) ===
// DO NOT edit the block below by hand. The publisher script appends here.
// BEGIN_NEWSLETTER_IMPORTS
import { announcementsIntroducingOpenmatesV09Chat } from "./data/announcements_introducing_openmates_v09";
import { announcementsApril2026UpdateChat } from "./data/announcements_april_2026_update";
// END_NEWSLETTER_IMPORTS

/** All newsletter demo chats, active + inactive. Filtered by helpers below. */
export const ALL_NEWSLETTER_CHATS: DemoChat[] = [
  // === Generated newsletter chat registrations (managed by publisher) ===
  // BEGIN_NEWSLETTER_REGISTRATIONS
  announcementsIntroducingOpenmatesV09Chat,
  announcementsApril2026UpdateChat,
// END_NEWSLETTER_REGISTRATIONS
];

const byChatId = new Map<string, DemoChat>();
const bySlug = new Map<string, DemoChat>();
for (const chat of ALL_NEWSLETTER_CHATS) {
  byChatId.set(chat.chat_id, chat);
  bySlug.set(chat.slug, chat);
}

/** Kinds encoded in a newsletter chat_id. */
export type NewsletterKind = "announcements" | "tips";

export function newsletterKindFromChatId(chatId: string): NewsletterKind | null {
  if (chatId.startsWith("announcements-")) return "announcements";
  if (chatId.startsWith("tips-")) return "tips";
  return null;
}

export function getNewsletterChatById(chatId: string): DemoChat | undefined {
  return byChatId.get(chatId);
}

export function getNewsletterChatBySlug(kind: NewsletterKind, slug: string): DemoChat | undefined {
  const chat = bySlug.get(slug);
  if (!chat) return undefined;
  const chatKind = newsletterKindFromChatId(chat.chat_id);
  return chatKind === kind ? chat : undefined;
}

/** Active chats only — used by sitemap + SEO pages. Inactive ones 404. */
export function getAllActiveNewsletterChats(): DemoChat[] {
  return ALL_NEWSLETTER_CHATS.filter((c) => (c as DemoChat & { is_active?: boolean }).is_active !== false);
}

export function getActiveNewsletterChatsByKind(kind: NewsletterKind): DemoChat[] {
  return getAllActiveNewsletterChats().filter((c) => newsletterKindFromChatId(c.chat_id) === kind);
}
